import re

def check_password_strength(password):
    score = 0
    feedback = []

    # Kural 1: Uzunluk (en az 8 karakter)
    if len(password) >= 8:
        score += 1
    else:
        feedback.append("Şifre en az 8 karakter uzunluğunda olmalı.")

    # Kural 2: Büyük harf
    if re.search(r"[A-Z]", password):
        score += 1
    else:
        feedback.append("Şifre en az bir büyük harf içermeli.")

    # Kural 3: Küçük harf
    if re.search(r"[a-z]", password):
        score += 1
    else:
        feedback.append("Şifre en az bir küçük harf içermeli.")

    # Kural 4: Rakam
    if re.search(r"\d", password):
        score += 1
    else:
        feedback.append("Şifre en az bir rakam içermeli.")

    # Kural 5: Özel karakter
    if re.search(r"[!@#$%^&*()_+{}\[\]:;<>,.?~\\-]", password):
        score += 1
    else:
        feedback.append("Şifre en az bir özel karakter (!@#$%^&*() vb.) içermeli.")

    strength_level = ""
    if score == 5:
        strength_level = "Çok Güçlü"
    elif score == 4:
        strength_level = "Güçlü"
    elif score == 3:
        strength_level = "Orta"
    elif score == 2:
        strength_level = "Zayıf"
    else:
        strength_level = "Çok Zayıf"

    return strength_level, feedback

if __name__ == "__main__":
    while True:
        password = input("Kontrol etmek istediğiniz şifreyi girin (çıkmak için 'q' tuşuna basın): ")
        if password.lower() == 'q':
            break

        strength, feedback = check_password_strength(password)
        print(f"Şifre Gücü: {strength}")
        if feedback:
            print("Eksiklikler:")
            for item in feedback:
                print(f"- {item}")
        print("-" * 30)
